#include<bits/stdc++.h>
using namespace std;
const int MAXN=2000+5;
int a[MAXN][MAXN]={0},dp[MAXN][MAXN]={0},n,m;
int main(){

    cin>>m>>n;
    for(int i=0;i<n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    for(int j=1;j<=m;j++){
        for(int i=0;i<n;i++){
            dp[i][j]=(min(dp[i][j-1],dp[(i-1+n)%n][j-1])+a[i][j]);
        }
    }
    int minn=1e9;
    for(int i=0;i<n;i++) minn=min(dp[i][m],minn);
    cout<<minn;
    return 0;
}
